1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. using ChurnPredictor.Models;
5. 
6. var builder = WebApplication.CreateBuilder(args);
7. 
8. // Train the model and register a pooled prediction engine (thread-safe)
9. var mlContext = new MLContext(seed: 42);
10. var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
11. var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
12. 
13. var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
14. var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
15. 
16. var labelMap = new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false };
17. 
18. var pipeline = mlContext.Transforms.Conversion.MapValue(
19.         "Label", labelMap, nameof(CustomerData.Churned))
20.     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
21.     .Append(mlContext.Transforms.Concatenate("Features",
22.         nameof(CustomerData.Age),
23.         nameof(CustomerData.Income),
24.         "RegionEncoded",
25.         nameof(CustomerData.PurchaseHistory)))
26.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
27.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
28.         labelColumnName: "Label",
29.         featureColumnName: "Features"));
30. 
31. var model = pipeline.Fit(split.TrainSet);
32. 
33. // Evaluate on test set
34. var predictions = model.Transform(split.TestSet);
35. var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
36. Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
37. 
38. mlContext.Model.Save(model, dataView.Schema, modelPath);
39. 
40. builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
41.     .FromFile(modelPath);
42. 
43. var app = builder.Build();
44. 
45. app.MapGet("/", () => "Churn Predictor API — POST to /predict");
46. 
47. app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
48. {
49.     var input = new CustomerData
50.     {
51.         Age = req.Age,
52.         Income = req.Income,
53.         Region = req.Region,
54.         PurchaseHistory = req.PurchaseHistory
55.     };
56.     var result = pool.Predict(input);
57.     return Results.Ok(new
58.     {
59.         WillChurn = result.PredictedLabel,
60.         Probability = result.Probability,
61.         Score = result.Score
62.     });
63. });
64. 
65. app.Run();
